const Q_PHYSICS_1995=[{"id": "objective>Physics>1995>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the dimension of pressure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure is defined as force per unit area. In terms of dimensions, force is Mass (M) times Acceleration (L/T^2) and area is Length squared (L^2). Therefore, the dimension of pressure is M/(L*T^2) which simplifies to ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>.</div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>1995>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The length of a displaced pendulum ball which passes its lowest point twice every seconds is [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.25 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.45 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.58m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The period of a simple pendulum is given by T = 2π√(L/g), where L is the length of the pendulum and g is the acceleration due to gravity. Given that the pendulum passes its lowest point twice every second, the period T is 0.5 seconds. Substituting T = 0.5 seconds and g = 10 m/s^2 into the formula, we can solve for L to get L = 0.25 m.</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>1995>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> When a ball rolls on a smooth level ground, the motion of its center is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">translational</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oscillatory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">random</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rotational</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a ball rolls on a smooth level ground, the motion of its center is translational. This is because all points on the ball move the same distance in the same direction over the same time period, which is the definition of translational motion.</div>", "topic": "MOTION: TYPES OF MOTION"}, {"id": "objective>Physics>1995>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the acceleration due to gravity 'g' on the moon, if g is 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> on the earth?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 0. 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.74ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.6ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.00ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The acceleration due to gravity on the moon is approximately 1/6th of that on Earth. Given that the acceleration due to gravity on Earth is 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, the acceleration due to gravity on the moon would be approximately 1.6ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. Therefore, the correct option is 3.</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>1995>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body is projected from the earth's surface with the intention of letting it escape from the earth's gravitational field. What is the minimum escape velocity of the body? [Earth's radius = 6.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>km, g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14 kms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">13 kms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 kms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">11 kms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Velocity = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2gR&nbsp;</span> <br/> = 2 x 6400 x 100 x 10 <br/> = 11 km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "GRAVITATIONAL FIELD : ESCAPE VELOCITY"}, {"id": "objective>Physics>1995>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A uniform rod PQ of length 1m and mass 2kg is pivoted at the end p. If load of 14N is placed at the center of the rod, find the force that should be applied vertically upwards at Q to maintain the rod at equilibrium horizontally [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">68N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">28N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"1995/jamnnew.png\" style=\"position:relative;max-width:100%;\"/> <br/> 1m long  <br/> taking the moment at P <br/> 34(0.5) = 1(Q) <br/> Q = 17N</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>1995>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A vehicle of mass m is driven by an engine of power P from rest. Find the minimum time it will take to acquire a speed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />P</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />2P</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mv<hr size=\"1\" />P</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mv<hr size=\"1\" />2P</td></tr></table></div></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">workdone<hr size=\"1\" />t</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">workdone</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">workdone<hr size=\"1\" />P</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />2P</td></tr></table></div></div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>1995>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements are TRUE about frictional force?  <br/> i. it is always a disadvantage  <br/> ii. it is sometimes a disadvantage  <br/> iii. it always exist where there is a relative motion of two bodies that are in contact  <br/> iv. it is sometimes very useful</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i, iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, iv only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii, iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iii, iv only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">it always exist where there is a relative motion of two bodies that are in contact   <br/> it is sometimes very useful</div>", "topic": "FRICTION"}, {"id": "objective>Physics>1995>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The energy contained in a wire when it extended by 0.02m by a force 500 N is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Energy = force × distance  <br/> E = 1/2 × 500 × 0.02 = 5J</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>1995>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hydraulic press has a large circular piston of radius 0.8m and a circular plunger of radius 0.2m. A force of 500N is exerted by the plunger. Find the force exerted on the piston</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8000N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4000N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2000N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">31N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure on piston = pressure on the plunger <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />A</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">500<hr size=\"1\" />π×0.2×0.2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />π×0.8×0.8</td></tr></table></div> <br/> F = 8000N</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>1995>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of an air bubble increases from the bottom to the top of a lake at constant temperature because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">atmospheric pressure acts on the surface of the lake</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure increases with depth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">density remains constant with pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the bubble experiences an upthrust</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of an air bubble increases from the bottom to the top of a lake at constant temperature because the pressure decreases with depth. This is due to the fact that pressure in a fluid increases with depth due to the weight of the fluid above. Therefore, as the bubble rises, the external pressure decreases, allowing the bubble to expand.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>1995>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Temperature is the measure of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quantity of heat transferred into the molecules of an object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mean kinetic energy of the molecules of the object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kinetic energy of any individual molecule of the substance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amount of work done by the molecules of the object</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Temperature is a measure of the average kinetic energy of the molecules of an object. Kinetic energy is the energy of motion, and in this case, it refers to the motion of the molecules. The faster the molecules are moving, the higher the temperature of the object.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>1995>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rectangular metal block of volume 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 273k is heated to 573k. If its coefficient of linear expansion is 1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, the percentage change of it volume is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.5%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.1%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Υ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∆V<hr size=\"1\" />V(θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></td><td style=\"text-align:center;\">×1.2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∆V<hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>(573-273)</td></tr></table></div> <br/> ∆V = 1.080 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%∆V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.080×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8-</span><hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> = 1.08% <br/> = 1.1%</div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>1995>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of wood floats inside water at room temperature with a fraction of it above the liquid surface. As the temperature of the water is raised, the part of the wood above the liquid will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease because the density of water decreases with temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase because the density of water decreases with temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases because the density of water increases with water temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase because the density of water increases with temperature</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As the temperature of water increases, its density decreases. Since the buoyant force acting on the piece of wood depends on the density of the liquid, as the water becomes less dense, the fraction of the wood submerged will decrease, causing a greater portion of the wood to float above the liquid surface.</div>", "topic": "LIQUIDS AT REST : LAW OF FLOATATION"}, {"id": "objective>Physics>1995>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equation P<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">z</span> = constant in charles' law when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">x = 1, y = -1, z = 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">x = 0, y = 1, z = -1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">x = 1, y = 0, z = -1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">x = 0, y = 1, z = 1</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Charle's law <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div></div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>1995>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric kettle with negligible heat capacity is rated at 2000W. If 2.0kg of water is put in it, how long will it take the temperature of water to rise from 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">O</span>C to 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">O</span>C?  <br/> [specific heat capacity of water = 4200Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 420s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">336s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">168s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48s</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H = mc∆θ <br/> H = 2000 × t = 2000t <br/> m = 2kg, c = 4200JKg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, ∆θ = 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C - 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C = 80<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C <br/> 2000t = 2(4200)(80)  <br/> 2000t = 672000 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">672000<hr size=\"1\" />2000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">336s</td></tr></table></div></div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>1995>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A temperature scale has a lower fixed point of 40mm and a upper fixed point of 200mm. What is the reading on this scale when a thermometer reads 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">33.3mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">36.0mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">96.0mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">136.0mm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"1995/junow.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100-0<hr size=\"1\" />60-0</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200-40<hr size=\"1\" />x-40</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100<hr size=\"1\" />60</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">160<hr size=\"1\" />x-40</td></tr></table></div> <br/> 10x - 400 = 960 <br/> 10x = 960 + 400 <br/> 10x = 1360 <br/> x = 136mm</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>1995>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A quantity of ice at 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is heated until the temperature of the heating vessel is 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. Which of the following constants is NOT required to determine the quantity of heat supplied to the vessel?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">specific heat capacity of ice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specific heat capacity of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specific latent heat of fusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specific latent heat of vaporization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">specific latent heat of vaporization is not needed because there is no vaporization in the process. </div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF FUSION~~QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>1995>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements give the TRUE difference between evaporation and boiling?  <br/> i. Evaporation occurs at all temperatures while boiling occurs at a fixed temperature for a given pressure.  <br/> ii. Evaporation is a surface phenomenon while boiling is an interior phenomenon.  <br/> iii. Evaporation is affected by surface area while boiling is not.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and ii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, ii, iii</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All the statements i, ii, iii are true differences between evaporation and boiling. Evaporation is a surface phenomenon that occurs at all temperatures and is affected by surface area. On the other hand, boiling is an interior phenomenon that occurs at a fixed temperature for a given pressure and is not affected by surface area.</div>", "topic": "CHANGE OF STATE : EVAPORATION AND BOILING"}, {"id": "objective>Physics>1995>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A well-lagged bar of length 100cm has its ends maintained at 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C and 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C respectively. What is the temperature at a point 60cm from the hotter end?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 58<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">62<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">64<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">76<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The temperature at a point 60cm from the hotter end is 40cm from the colder end <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100-40<hr size=\"1\" />100-c</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />100-40</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">60<hr size=\"1\" />100-c</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100-0<hr size=\"1\" />60</td></tr></table></div> <br/> 3600 = 10000 -100c <br/> 100c = 10000 - 3600 <br/> 100c = 6400 <br/> c = 64<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>1995>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the exclusive property of a transverse wave?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compression</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">polarization is the action of restricting the vibrations of a transverse wave, especially light, wholly or partially to one direction.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>1995>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The wavelength of signals from a radio transmitter is 1500mm and the frequency is 200kHz. What is the wavelength for a transmitter operating at 1000kHz?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7500mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15mm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 1500 × 200000  = 100000 × λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1500×200000<hr size=\"1\" />1000000</td></tr></table></div> <br/> λ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 300mm</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>1995>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between sound waves and light waves is that sound waves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are transverse while light waves are longitudinal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">require a medium to travel while light waves does not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can be diffracted but light waves cannot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cannot be reflected but light waves can</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main difference between sound waves and light waves is that sound waves require a medium to travel, while light waves do not. Sound waves are mechanical waves that propagate through a medium (like air, water, or a solid material), while light waves are electromagnetic waves that can travel through the vacuum of space.</div>", "topic": "PROPAGATION OF SOUND WAVES~~WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>1995>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pitch of an acoustic device can be increased by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing the frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the amplitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the loudness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the intensity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pitch of a sound is determined by its frequency. Higher frequency sounds have a higher pitch. Therefore, increasing the frequency of an acoustic device will increase its pitch. Amplitude, loudness, and intensity are related to the volume or strength of the sound, not its pitch.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>1995>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Total eclipse of the sun occurs when the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">earth is between the moon and the sun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sun is between the moon and the earth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moon is between the sun and the earth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ozone layer is threatened</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total solar eclipses happen when the New Moon comes between the Sun and Earth and casts the darkest part of its shadow, the umbra, on Earth. A total eclipse is spectacular to see. During a total eclipse of the Sun, the Moon covers the entire disk of the Sun.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>1995>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the approximate critical angle for total internal reflection for diamond if the refractive index of diamond is 2.42?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">21<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">22<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">23<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">24<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">sinC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />η</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">sinC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2.42</td></tr></table></div> <br/> sinC = 0.4132 <br/> C = sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>0.4231 <br/> C = 24<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>1995>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A real object is placed at a distance u cm in front of a curved mirror of focal length f cm. If the image is upright and magnified, then the mirror is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">convex and u =2f</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concave and u = 2f</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convex and u = f</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concave and u = f</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An upright and magnified image is formed by a concave mirror when the object is placed between the focus and the pole of the mirror. This means the object distance (u) is less than the focal length (f). Therefore, the mirror is concave and u is not equal to 2f. None of the options perfectly matches the correct answer, but option 2 is the closest.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : FORMATION OF IMAGES BY PLANE, CONCAVE AND CONVEX MIRRORS AND RAY DIAGRAMS"}, {"id": "objective>Physics>1995>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs of colours gives the widest separation in the spectrum of white light?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Red and Violet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green and Yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red and Indigo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yellow and Violet</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">White light is composed of light of different wavelengths (colors) i.e. violet, indigo, blue, green, yellow and red. Red has the highest wavelength and violet the lowest. Wavelength is inversely proportional to the deviation in the path of the light. Red light suffers the least amount of deviation and violet the most.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>1995>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two parallel plates at a distance of 8.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m apart are maintained at a p.d of 600 volts with the negative plate earthed. What is the electric field strength?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.8 Vm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">75.0Vm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4800.0Vm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">75000.0Vm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electric field strength (E) between two parallel plates is given by the formula E = V/d, where V is the voltage and d is the distance between the plates. Substituting the given values, E = 600V / 8.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m = 75000.0Vm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Therefore, the electric field strength is 75000.0Vm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>1995>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At different locations on the earth's surface, the earth's magnetic field is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the same in magnitude and direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same in magnitude but different in direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different in both magnitude and direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different in magnitude but different in direction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Earth's magnetic field varies both in strength (magnitude) and direction depending on the location on the Earth's surface. This is due to the Earth's magnetic field being generated by a dynamo effect caused by the movement of molten iron within the Earth's outer core.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : EARTH’S MAGNETIC FIELD"}, {"id": "objective>Physics>1995>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a resistance is halved in value and the potential difference across it is tripled, then the ratio of the new current to the old one is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 : 6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 : 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6 : 1</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />R</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>×R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>×V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">,</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2(3V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />1</td></tr></table></div></div>", "topic": "CURRENT ELECTRICITY : OHM’S LAW"}, {"id": "objective>Physics>1995>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 12V battery has an internal resistance of 0.5Ω. If a cable of 1.0Ω resistance is connected across the two terminals of the battery, the current drawn from the battery is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16.0A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4A</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">E = I(R+r) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<hr size=\"1\" />R+r</td></tr></table></div> <br/> E = 12V, R = 1Ω , r = 0.5Ω <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />1+0.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />1.5</td></tr></table></div> <br/> I = 8A</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>1995>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The purpose of a dielectric material in a parallel plate capacitor is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase its capacitance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease its capacitance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insulate the plate from each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the magnetic field between the plates</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The purpose of a dielectric material in a parallel plate capacitor is to increase its capacitance. A dielectric material is a substance that is poor conductor of electricity, but an efficient supporter of electrostatic field. When a dielectric is placed between the plates of a capacitor, it increases the capacitance because it increases the ability of the capacitor to store charge for a given potential difference across its plates.</div>", "topic": "CAPACITORS : CAPACITANCE OF A CAPACITORS"}, {"id": "objective>Physics>1995>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric current of 2 amperes flows in a heating coil of resistance 50 ohms for 3 minutes 20 seconds. Determine the heat produced</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40.0kJ</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Rt <br/> H = 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × 50 × 200  <br/> = 40000J  <br/> = 40KJ</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>1995>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the maximum voltage across a 100 ohms resistor is 20V, then the maximum power it can dissipate is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.00W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.00W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25W</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />R</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">400<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4W</td></tr></table></div></div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>1995>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is required to convert a milliammeter to an ammeter?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A high resistance in parallel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A high resistance in series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A low resistance in parallel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A low resistance in series</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To convert a milliammeter to an ammeter, a low resistance (shunt) is connected in parallel to the milliammeter. The shunt provides an alternative path for the current, allowing the milliammeter to measure higher currents without being damaged.</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>1995>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary winding of a transformer has 400 turns and its secondary has 100 turns. If a source of e.m.f. of 12V is applied to the primary, the secondary e.m.f. will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td></tr></table></div> <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 400, N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = 100, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 12V , V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">400<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3V</td></tr></table></div></div>", "topic": "ELECTROMAGNETIC INDUCTION : TRANSFORMERS"}, {"id": "objective>Physics>1995>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A light of energy 5eV falls on a metal and the electrons with a maximum kinetic energy of 2eV are ejected. The work function of the metal is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.4eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.0eV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">E = hf + w<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> <br/> w<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = E - hf   <br/> E = kinetic energy, w<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = work function, hf = light energy <br/> w<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = 5eV - 2eV = 3eV</div>", "topic": "ELEMENTARY MODERN PHYSICS : PHOTOELECTRIC EFFECTS"}, {"id": "objective>Physics>1995>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The half-life of a radio-active element is 9 days, what fraction of atoms has decayed in 36 days?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />16</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">15<hr size=\"1\" />16</td></tr></table></div></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">----</td><td style=\"text-align:center;\">9days</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">-----</td><td style=\"text-align:center;\">18</td><td style=\"text-align:center;\">days</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />8</td><td style=\"text-align:center;\">--------27days</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />16</td><td style=\"text-align:center;\">------------</td><td style=\"text-align:center;\">36days</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />16</td><td style=\"text-align:center;\">will</td><td style=\"text-align:center;\">remain</td><td style=\"text-align:center;\">after</td><td style=\"text-align:center;\">36</td><td style=\"text-align:center;\">days</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">therefore,</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15<hr size=\"1\" />16</td><td style=\"text-align:center;\">decayed</td></tr></table></div></div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>1995>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An alternating source is connected in series to a capacitor of capacitive reactance 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>√3 and a resistor of resistance 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> Ohms. The Impedance of the circuit is...</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2000√3 Ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2000 Ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000√3 Ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000 Ohms</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Z = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>+X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> <br/> Z = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">(10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>+(10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> <br/> Z = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3(10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>)+(10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>)&nbsp;</span> <br/> Z = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">(3+1)10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>&nbsp;</span> <br/> Z = 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> Ohms <br/> Z = 2000 Ohms</div>", "topic": "SIMPLE A. C. CIRCUITS : REACTANCE AND IMPEDANCE"}, {"id": "objective>Physics>1995>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the above fig, PQ and R are vectors, which of the following options, gives a correct relationship between the vectors? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P = Q + R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P = Q - R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P = R - Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P + Q + R = O</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Based on the direction of the vectors, <br/> P - Q - R = 0 <br/> Rearranging the vectors: <br/> P = Q + R</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>1995>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The value of T in the figure above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.8N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40.0N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">∑fy = 0 <br/> Tsin30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> + Tsin30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> = 20 <br/> 0.5T + 0.5T = 20 <br/> T = 20N</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>1995>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The acceleration of the system show above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The acceleration of the system is a <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>g - m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>gsinθ = (m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)a <br/> 30(10) - 20(10)sin30 = (20+30)a <br/> 300 - 100 = 50a <br/> 200 = 50a <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200<hr size=\"1\" />50</td></tr></table></div> <br/> a = 4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>1995>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A body of mass 40kg is being dragged along the floor by a rope inclined at 60 degrees to the horizontal. The frictional force between the box and the floor is 100N and the tension on the rope is 300N. How much work is done by dragging the box for a distance of 4m </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">680J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100J</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F - F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span> = ma <br/> F = Tcos60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> = 300cos60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> = 150N <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span> = 100N, m = 40kg,  <br/> ma = 150 - 100 =50N <br/> workdone = F × d = 50 × 4 = 200J</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>1995>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The fig above shows two similar bulbs X and Y connected to suitable power supply with F as an appropriate fuse rating, if the filament of X breaks then the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Brightness Of Y will reduce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brightness Of Y will remain constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brightness Of Y will increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fuse F will blow</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagram above shows a Parallel circuit <br/> If one of the parallel path is broken, current will continue to flow in other parts. <br/>  Voltage is the same across each component of the parallel circuit. <br/> The brightness of a light bulb is given by its power. P = I2R, <br/> and so brightness depends on current and resistance. <br/> Hence; the brightness of Y will not be affected except for a variation in resistance property.</div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>1995>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The resultant capacitance in the fig above is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15.0µF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.8µF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.3µF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8µF</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Series connection of capacitors = the sum of the reciprocal of the individual capacitance while parallel is the sum of the capacitance <br/> 2µF and 4µF are in parallel <br/> C = 6µF <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6+4+2+3<hr size=\"1\" />12</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15<hr size=\"1\" />12</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />15</td></tr></table></div> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> = 0.8µF</div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>1995>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An alternating source is connected in series to a capacitor of capacity reactance of 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span> and resistor of a resistance 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> Ohms. The impedance of the circuit is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2000 &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span> Ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2000 Ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000 &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span> Ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000 Ohms</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The impedance of a circuit with a capacitor and a resistor in series is given by the formula Z = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">R^2 + Xc^2&nbsp;</span>, where R is the resistance and Xc is the capacitive reactance. In this case, R = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> Ohms and Xc = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>. Therefore, Z = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">(10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>)^2 + (10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>)^2&nbsp;</span> = 2000 Ohms.</div>", "topic": "SIMPLE A. C. CIRCUITS : REACTANCE AND IMPEDANCE"}, {"id": "objective>Physics>1995>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The half-life of a radioactive element is 9 days. What fraction of atoms has decayed in 36 days?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />16</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">15<hr size=\"1\" />16</td></tr></table></div></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1/2 -------- 9days <br/> 1/4 -------- 18 days <br/> 1/8 --------- 27 days <br/> 1/16 -------- 36 days <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />16</td><td style=\"text-align:center;\">will</td><td style=\"text-align:center;\">remain</td><td style=\"text-align:center;\">after</td><td style=\"text-align:center;\">36</td><td style=\"text-align:center;\">days</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Therefore</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />16</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15<hr size=\"1\" />16</td><td style=\"text-align:center;\">decayed</td></tr></table></div></div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>1995>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A  light of energy 5eV falls on a metal and the electrons with a maximum kinetic energy of 2eV are rejected. The work function ofthe metal i</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.4eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.0eV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The work function of a metal is the minimum energy required to remove an electron from the metal. It is given by the difference between the energy of the incident light and the maximum kinetic energy of the ejected electrons. Therefore, the work function is 5eV - 2eV = 3eV.</div>", "topic": "ELEMENTARY MODERN PHYSICS : PHOTOELECTRIC EFFECTS"}];
